// 1. Text Selection / Sentence Selection Bridge
if (e.data?.type === 'TEXT_SELECT' || e.data?.type === 'SENTENCE_SELECTED') {
    const { text, rect } = e.data;

    // Calculate safe X position within the 909px book bounds
    const menuWidthInBookSpace = 260 / scaleFactor;
    const halfWidth = menuWidthInBookSpace / 2;
    const edgePadding = 15 / scaleFactor;

    let targetX = rect.x + (rect.width / 2);
    targetX = Math.max(halfWidth + edgePadding, Math.min(909 - halfWidth - edgePadding, targetX));

    // Smart Vertical Positioning: Check if we have clearance above the text
    const vp = document.getElementById('viewport');
    let isAbove = true;
    if (vp) {
        const screenY = (rect.y * scaleFactor) - vp.scrollTop;
        if (screenY < 320) isAbove = false; // If less than 320px screen space above, spawn below
    }

    setContextMenu({
        x: targetX,
        y: isAbove ? rect.y : rect.y + rect.height,
        isAbove: isAbove,
        text: text
    });
}

