ops.replace_with:
// 1. Text Selection / Sentence Selection Bridge
if (e.data?.type === 'TEXT_SELECT' || e.data?.type === 'SENTENCE_SELECTED') {
    const { text, rect } = e.data;
    const vp = document.getElementById('viewport');

    // --- 1. Horizontal Clamping (X) ---
    // The menu centers on the X anchor. We must ensure the edges don't overflow the 909px book container.
    const menuWidthPx = 260;
    const menuHalfWidthBook = (menuWidthPx / 2) / scaleFactor;
    const paddingBook = 10 / scaleFactor;

    let targetX = rect.x + (rect.width / 2);
    targetX = Math.max(menuHalfWidthBook + paddingBook, Math.min(909 - menuHalfWidthBook - paddingBook, targetX));

    // --- 2. Vertical Smart Positioning (Y) ---
    // Default to BELOW. Flip to ABOVE only if obstructed by bottom edge.
    const menuHeightPx = 200; // Approx height including padding
    const screenHeight = window.innerHeight;
    const scrollTop = vp ? vp.scrollTop : 0;

    // Calculate Screen Coordinates of the selection
    const rectScreenBottom = ((rect.y + rect.height) * scaleFactor) - scrollTop;
    const rectScreenTop = (rect.y * scaleFactor) - scrollTop;

    let isAbove = false; // Default preference: Below
    const spaceBelow = screenHeight - rectScreenBottom;

    // If not enough space below (less than menu height + buffer), try above
    if (spaceBelow < menuHeightPx + 20) {
        isAbove = true;
        // Failsafe: If sticking it above pushes it off the top of the screen, force it below (overlaying text is better than off-screen)
        if (rectScreenTop < menuHeightPx + 50) {
            isAbove = false;
        }
    }

    setContextMenu({
        x: targetX,
        y: isAbove ? rect.y : rect.y + rect.height,
        isAbove: isAbove,
        text: text
    });
}

