if (isDraggingCtx && contextMenu && ctxMenuRef.current) {
    // --- 1. Calculate Raw New Position (Book Space) ---
    let newX = (clientX / scaleFactor) - dragOffset.current.x;
    let newY = (clientY / scaleFactor) - dragOffset.current.y;

    // --- 2. Clamp X to Book Boundaries ---
    // Menu is centered on X, width 260px (scaled)
    const menuHalfWidthBook = (130 / scaleFactor);
    newX = Math.max(menuHalfWidthBook, Math.min(909 - menuHalfWidthBook, newX));

    // --- 3. Clamp Y to Visible Viewport ---
    // We need to prevent dragging off the top/bottom of the visible screen area.
    // Note: 'newY' is the anchor point. The menu body is offset by CSS top/bottom: 12px.
    const vp = viewportRef.current;
    if (vp) {
        const scrollTop = vp.scrollTop;
        const viewHeight = window.innerHeight;
        const visibleTopBook = scrollTop / scaleFactor;
        const visibleBottomBook = (scrollTop + viewHeight) / scaleFactor;

        const menuHeightBook = 220 / scaleFactor; // Approx height + margin
        const offsetBook = 12 / scaleFactor;

        if (contextMenu.isAbove) {
            // Anchor is at bottom of menu. 
            // Menu occupies [newY - offset - height] to [newY - offset]
            // Clamp Anchor so Top of menu >= VisibleTop
            const minAnchorY = visibleTopBook + offsetBook + menuHeightBook;
            const maxAnchorY = visibleBottomBook + offsetBook; // Let it touch bottom edge
            newY = Math.max(minAnchorY, Math.min(maxAnchorY, newY));
        } else {
            // Anchor is at top of menu.
            // Menu occupies [newY + offset] to [newY + offset + height]
            // Clamp Anchor so Bottom of menu <= VisibleBottom
            const minAnchorY = visibleTopBook - offsetBook;
            const maxAnchorY = visibleBottomBook - offsetBook - menuHeightBook;
            newY = Math.max(minAnchorY, Math.min(maxAnchorY, newY));
        }
    }

    ctxMenuRef.current.style.left = `${newX}px`;
    ctxMenuRef.current.style.top = `${newY}px`;
    dragOffset.current.lastCtxX = newX; 
    dragOffset.current.lastCtxY = newY;
}

