    // --- NATIVE LINGUISTIC ENGINE STRATEGY ---
    // We temporarily enable selection to use the browser's powerful 'modify' API
    // which handles multi-line, nested nodes, and complex punctuation correctly.

    try {
        const sel = win.getSelection();
        // 1. Temporarily unlock selection
        const prevSelect = doc.body.style.webkitUserSelect;
        doc.body.style.webkitUserSelect = 'text';
        doc.body.style.userSelect = 'text';

        // 2. Place caret at click
        sel.removeAllRanges();
        sel.addRange(range);

        // 3. Expand to Sentence (Native)
        // This handles wrapping lines and nested tags automatically
        if (sel.modify) {
            sel.modify('move', 'backward', 'sentence');
            sel.modify('extend', 'forward', 'sentence');
        }

        // 4. Capture the Result
        const sentenceRange = sel.getRangeAt(0).cloneRange();

        // 5. Cleanup (Hide native selection immediately)
        sel.removeAllRanges();
        doc.body.style.webkitUserSelect = prevSelect;
        doc.body.style.userSelect = prevSelect;

        // 6. Apply Custom Highlight
        if (sentenceRange && !sentenceRange.collapsed) {
            const highlight = new win.Highlight(sentenceRange);
            win.CSS.highlights.set("sentence-focus", highlight);

            // 7. Return Metadata for Context Menu
            const rects = sentenceRange.getClientRects();
            // Use the bounding rect of the union of rects
            const boundingRect = sentenceRange.getBoundingClientRect();

            return {
                found: true,
                text: sentenceRange.toString(),
                rect: {
                    x: boundingRect.x,
                    y: boundingRect.y,
                    width: boundingRect.width,
                    height: boundingRect.height
                }
            };
        }
    } catch (e) {
        console.error("Native Sentence Select Failed:", e);
        // Fallback: Just highlight the word if sentence detection fails
        win.CSS.highlights.clear();
    }

    return { found: false };
};

