 812 |                 // --- HELPER FUNCTIONS FOR TEXT STREAMING ---
 813 | 
 814 |                 // Finds where a specific text node starts relative to the container's full text
 815 |                 function getGlobalOffset(root, targetNode) {
 816 |                     const walker = doc.createTreeWalker(root, NodeFilter.SHOW_TEXT, null, false);
 817 |                     let offset = 0;
 818 |                     while (walker.nextNode()) {
 819 |                         if (walker.currentNode === targetNode) return offset;
 820 |                         offset += walker.currentNode.textContent.length;
 821 |                     }
 822 |                     return 0;
 823 |                 }
 824 | 
 825 |                 // Pure string logic to find sentence start/end
 826 |                 function findSentenceBounds(text, index) {
 827 |                     if (index < 0 || index >= text.length) return null;
 828 | 
 829 |                     const terminators = /[.!?](\s|$)/;
 830 |                     
 831 |                     // Backward scan for start
 832 |                     let start = 0;
 833 |                     for (let i = index; i >= 0; i--) {
 834 |                         const char = text[i];
 835 |                         // Check if we hit a terminator. 
 836 |                         // NOTE: We check i-1 to ensure we don't stop on the punctuation of the *previous* sentence if we are at space
 837 |                         if (terminators.test(char + (text[i+1] || ''))) {
 838 |                             start = i + 2; // Move past ". "
 839 |                             break;
 840 |                         }
 841 |                     }
 842 | 
 843 |                     // Forward scan for end
 844 |                     let end = text.length;
 845 |                     for (let i = index; i < text.length; i++) {
 846 |                         if (terminators.test(text[i] + (text[i+1] || ''))) {
 847 |                             end = i + 1; // Include the "."
 848 |                             break;
 849 |                         }
 850 |                     }
 851 | 
 852 |                     return { start, end };
 853 |                 }
 854 | 
 855 |                 // The Magic: Maps string indices back to exact DOM Node + Offset
 856 |                 function createRangeFromGlobalOffsets(rootDoc, rootNode, startOffset, endOffset) {
 857 |                     const range = rootDoc.createRange();
 858 |                     const walker = rootDoc.createTreeWalker(rootNode, NodeFilter.SHOW_TEXT, null, false);
 859 |                     let currentPos = 0;
 860 |                     let startFound = false;
 861 |                     let endFound = false;
 862 | 
 863 |                     while (walker.nextNode()) {
 864 |                         const node = walker.currentNode;
 865 |                         const length = node.textContent.length;
 866 |                         const nextPos = currentPos + length;
 867 | 
 868 |                         // Found Start?
 869 |                         if (!startFound && startOffset >= currentPos && startOffset < nextPos) {
 870 |                             range.setStart(node, startOffset - currentPos);
 871 |                             startFound = true;
 872 |                         }
 873 | 
 874 |                         // Found End?
 875 |                         if (!endFound && endOffset >= currentPos && endOffset <= nextPos) {
 876 |                             range.setEnd(node, endOffset - currentPos);
 877 |                             endFound = true;
 878 |                         }
 879 | 
 880 |                         if (startFound && endFound) break;
 881 |                         currentPos = nextPos;
 882 |                     }
 883 | 
 884 |                     return (startFound && endFound) ? range : null;
 885 |                 }
 886 |             } catch (err) {
 887 |                 console.error("Iframe Load Error:", err);
 888 |             }
 889 |         }, 100);
 890 |     };
