        interactive.style.filter = 'brightness(0.8)';
        setTimeout(() => { interactive.style.transform = ''; interactive.style.filter = ''; }, 100);
        interactive.click();
        win.CSS?.highlights?.clear();
        return { found: true, isAction: true };
    }

    if (!win.CSS || !win.CSS.highlights) return false;

    let range;
    if (doc.caretRangeFromPoint) {
        range = doc.caretRangeFromPoint(clientX, clientY);
    }

    const targetNode = range?.startContainer;
    const targetElement = targetNode?.nodeType === 3 ? targetNode.parentElement : targetNode;

    // Rule: Prevent interaction with Question Cards
    if (targetElement?.closest('.miron-portal-container')) {
        win.CSS.highlights.clear();
        return { found: true, isAction: true };
    }

    if (!range || targetNode.nodeType !== 3) {
        win.CSS.highlights.clear();
        return { found: false };
    }

    // --- TEXT-STREAM STRATEGY ---
    // Robustly handles multi-line wrapping and nested tags by treating
    // the container content as a flat string first.
    try {
        // 1. Find the semantic container (Paragraph or Page)
        const container = targetElement.closest('p, div.text-container, .page-content, .page, article') || doc.body;

        // 2. Get global offsets
        const fullText = container.textContent;
        const clickGlobalOffset = getGlobalOffset(container, targetNode) + range.startOffset;

        // 3. Find Sentence Boundaries in the string
        const bounds = findSentenceBounds(fullText, clickGlobalOffset);
        if (!bounds) {
             win.CSS.highlights.clear();
             return { found: false };
        }

        // 4. Map back to DOM Range
        const sentenceRange = createRangeFromGlobalOffsets(doc, container, bounds.start, bounds.end);

        if (sentenceRange) {
            // 5. Apply Highlight
            const highlight = new win.Highlight(sentenceRange);
            win.CSS.highlights.set("sentence-focus", highlight);

            // 6. Return Metadata for Context Menu
            const boundingRect = sentenceRange.getBoundingClientRect();

            return {
                found: true,
                text: sentenceRange.toString(),
                rect: {
                    x: boundingRect.x,
                    y: boundingRect.y,
                    width: boundingRect.width,
                    height: boundingRect.height
                }
            };
        }
    } catch (e) {
        console.error("Text-Stream Select Failed:", e);
        win.CSS.highlights.clear();
    }
    return { found: false };
};

// --- HELPER FUNCTIONS FOR TEXT STREAMING ---

// Finds where a specific text node starts relative to the container's full text
function getGlobalOffset(root, targetNode) {
    const walker = doc.createTreeWalker(root, NodeFilter.SHOW_TEXT, null, false);
    let offset = 0;
    while (walker.nextNode()) {
        if (walker.currentNode === targetNode) return offset;
        offset += walker.currentNode.textContent.length;
    }
    return 0;
}

// Pure string logic to find sentence start/end
function findSentenceBounds(text, index) {
    if (index < 0 || index >= text.length) return null;

    const terminators = /[.!?](\s|$)/;

    // Backward scan for start
    let start = 0;
    for (let i = index; i >= 0; i--) {
        const char = text[i];
        // Check if we hit a terminator. 
        // NOTE: We check i-1 to ensure we don't stop on the punctuation of the *previous* sentence if we are at space
        if (terminators.test(char + (text[i+1] || ''))) {
            start = i + 2; // Move past ". "
            break;
        }
    }

    // Forward scan for end
    let end = text.length;
    for (let i = index; i < text.length; i++) {
        if (terminators.test(text[i] + (text[i+1] || ''))) {
            end = i + 1; // Include the "."
            break;
        }
    }

    return { start, end };
}

// The Magic: Maps string indices back to exact DOM Node + Offset
function createRangeFromGlobalOffsets(rootDoc, rootNode, startOffset, endOffset) {
    const range = rootDoc.createRange();
    const walker = rootDoc.createTreeWalker(rootNode, NodeFilter.SHOW_TEXT, null, false);
    let currentPos = 0;
    let startFound = false;
    let endFound = false;

    while (walker.nextNode()) {
        const node = walker.currentNode;
        const length = node.textContent.length;
        const nextPos = currentPos + length;

        // Found Start?
        if (!startFound && startOffset >= currentPos && startOffset < nextPos) {
            range.setStart(node, startOffset - currentPos);
            startFound = true;
        }

        // Found End?
        // Use <= nextPos to allow ending at the very end of a node
        if (!endFound && endOffset >= currentPos && endOffset <= nextPos) {
            range.setEnd(node, endOffset - currentPos);
            endFound = true;
        }

        if (startFound && endFound) break;
        currentPos = nextPos;
    }

    return (startFound && endFound) ? range : null;
}

