// --- OPTIMIZED SINGLE-PASS HIGHLIGHTER ---
win.highlightAt = (clientX, clientY) => {
    // 1. Check for Interactive Miron Elements
    const hitElement = doc.elementFromPoint(clientX, clientY);
    const interactive = hitElement?.closest('.q-opt-btn, .q-submit, .q-exam-launcher');

    if (interactive) {
        interactive.style.transform = 'scale(0.92)';
        interactive.style.filter = 'brightness(0.8)';
        setTimeout(() => { interactive.style.transform = ''; interactive.style.filter = ''; }, 100);
        interactive.click();
        win.CSS?.highlights?.clear();
        return { found: true, isAction: true };
    }

    if (!win.CSS || !win.CSS.highlights) return false;

    let range;
    if (doc.caretRangeFromPoint) {
        range = doc.caretRangeFromPoint(clientX, clientY);
    }

    if (!range) {
        win.CSS.highlights.clear();
        return { found: false };
    }

    let targetNode = range.startContainer;

    // Fix: If click hits container element, drill down to text node
    if (targetNode.nodeType === 1) {
        const child = targetNode.childNodes[range.startOffset];
        if (child && child.nodeType === 3) {
            targetNode = child;
            range.setStart(targetNode, 0);
        } else if (targetNode.firstChild && targetNode.firstChild.nodeType === 3) {
            targetNode = targetNode.firstChild;
            range.setStart(targetNode, 0);
        } else {
            // Missed text entirely
            win.CSS.highlights.clear();
            return { found: false };
        }
    }

    const targetElement = targetNode.nodeType === 3 ? targetNode.parentElement : targetNode;

    // Rule: Prevent interaction with Question Cards
    if (targetElement?.closest('.miron-portal-container')) {
        win.CSS.highlights.clear();
        return { found: true, isAction: true };
    }

    // --- SINGLE-PASS TOKENIZATION ---
    try {
        // 1. Find the semantic container (Page or Article)
        const container = targetElement.closest('div.text-container, .page-content, .page, article') || doc.body;

        // 2. Generate Map (O(N) - One pass only)
        const textNodes = [];
        let fullText = "";
        let clickGlobalOffset = -1;

        const walker = doc.createTreeWalker(container, NodeFilter.SHOW_TEXT, null, false);
        while(walker.nextNode()) {
            const node = walker.currentNode;
            const txt = node.textContent;
            const start = fullText.length;
            fullText += txt;
            const end = fullText.length;

            textNodes.push({ node, start, end });

            if (node === targetNode) {
                clickGlobalOffset = start + range.startOffset;
            }
        }

        if (clickGlobalOffset === -1) {
             win.CSS.highlights.clear();
             return { found: false };
        }

        // 3. Find Sentence Boundaries (String Op - Fast)
        const bounds = findSentenceBounds(fullText, clickGlobalOffset);
        if (!bounds) {
             win.CSS.highlights.clear();
             return { found: false };
        }

        // 4. Map boundaries back to Ranges (Array Lookup - Fast)
        const sentenceRange = doc.createRange();

        // Find Start Node
        const startNodeObj = textNodes.find(n => bounds.start >= n.start && bounds.start < n.end);
        if (startNodeObj) sentenceRange.setStart(startNodeObj.node, bounds.start - startNodeObj.start);
        else sentenceRange.setStart(textNodes[0].node, 0); // Fallback

        // Find End Node
        // Using <= end allows catching the exact end of a node
        const endNodeObj = textNodes.find(n => bounds.end > n.start && bounds.end <= n.end);
        if (endNodeObj) sentenceRange.setEnd(endNodeObj.node, bounds.end - endNodeObj.start);
        else {
            const last = textNodes[textNodes.length - 1];
            sentenceRange.setEnd(last.node, last.end - last.start);
        }

        // 5. Apply Highlight
        const highlight = new win.Highlight(sentenceRange);
        win.CSS.highlights.set("sentence-focus", highlight);

        // 6. Return Metadata
        const boundingRect = sentenceRange.getBoundingClientRect();
        return {
            found: true,
            text: sentenceRange.toString(),
            rect: {
                x: boundingRect.x,
                y: boundingRect.y,
                width: boundingRect.width,
                    height: boundingRect.height
            }
        };

    } catch (e) {
        console.error("Fast-Select Error:", e);
        win.CSS.highlights.clear();
    }
    return { found: false };
};

